require "config.Define"
require "ui.window.GUIIllustrationItem"
require "config.ItemConfig"

local GUIIllustrationDescription = class("UIIllustrationDescription", IGUILayout)

function GUIIllustrationDescription:onLoad()
    self.num = 0
    self.status = true
    self.id = 0

    self:getChildWindow("Illustrated-Description-Title", GUIType.StaticText):SetText(Lang:getString("lucky_sky_illustration_desc_title"))
    self.llClose = self:getChildWindow("Illustrated-Description-Close", GUIType.Layout)
    self.tvName = self:getChildWindow("Illustrated-Description-Name", GUIType.StaticText)
    self.tvDesc = self:getChildWindow("Illustrated-Description-Desc", GUIType.StaticText)
    self.tvNum = self:getChildWindow("Illustrated-Description-Num", GUIType.StaticText)
    self.ivIcon = self:getChildWindow("Illustrated-Description-Icon", GUIType.StaticImage)
    self.btnLike = self:getChildWindow("Illustrated-Description-Like", GUIType.Button)

    self.llClose:registerEvent(GUIEvent.Click, function()
        self:hide()
    end)

    self.btnLike:registerEvent(GUIEvent.ButtonClick, function()
        if self.status == true then
            self:onLikeClick()
        end
    end)
end

function GUIIllustrationDescription:setDesc(id)
    local item = ItemConfig:getItemById(id)
    if item == nil then
        return
    end

    self.id = id
    self.tvName:SetText(Lang:getString(item.name))
    self.tvDesc:SetText(Lang:getString(item.desc))
    self:show()
end

function GUIIllustrationDescription:onShow()
    self:getLikeNum(function(info, code)
        self:updateLikeNum(info, code)
    end)
end

function GUIIllustrationDescription:onLikeClick()
    self:sendLike(function(info, code)
        if code == 1 then
            self.status = false
            self.num = self.num + 1
            self:resetStatus()
        end
    end)
end

function GUIIllustrationDescription:updateLikeNum(info, code)
    if code == 1 then
        if info then
            self.status = info.status == 0
            self.num = info.praiseCount
            self:resetStatus()
        end
    end
end

function GUIIllustrationDescription:resetStatus()
    local btnImg = "set:lucky_sky_illustrated.json image:unlike"
    if self.status == false then
        btnImg = "set:lucky_sky_illustrated.json image:like"
    end
    self.ivIcon:SetImage(btnImg)
    self.tvNum:SetText(self.num)
end

function GUIIllustrationDescription:getLikeNum(callback)
    local path = "/gameaide/api/v1/game/props/praise/{userId}"
    path = string.gsub(path, "{userId}", tostring(CGame.Instance():getPlatformUserId()))

    local params = {
        { "gameId", "g1054" },
        { "propId", tostring(self.id) }
    }
    WebService.asyncGet(path, params, callback)
end

function GUIIllustrationDescription:sendLike(callback)
    local path = "/gameaide/api/v1/game/props/praise/{userId}"
    path = string.gsub(path, "{userId}", tostring(CGame.Instance():getPlatformUserId()))
    local body = {}
    local params = {
        { "gameId", "g1054" },
        { "propId", tostring(self.id) }
    }
    WebService.asyncPost(path, params, json.encode(body), callback)
end

return GUIIllustrationDescription